import { Link, useLocation, useNavigate } from 'react-router-dom';

function AdminSidebar() {
  const location = useLocation();
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user') || '{}');
  const isActive = (p) => location.pathname === p;

  const menuItems = [
    { path: '/admin', icon: '📊', label: 'Overview' },
    { path: '/admin/create-event', icon: '➕', label: 'Create Event' },
    { path: '/admin/manage-events', icon: '📝', label: 'Manage Events' },
    { path: '/admin/bookings', icon: '🎫', label: 'All Bookings' },
  ];

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  return (
    <aside style={{ width: '230px', minHeight: '100vh', background: '#2d1f1f', display: 'flex', flexDirection: 'column', flexShrink: 0 }}>

      {/* Header */}
      <div style={{ padding: '1.5rem', borderBottom: '1px solid rgba(201,169,154,0.2)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '1rem' }}>
          <div style={{ width: '32px', height: '32px', background: 'linear-gradient(135deg, #c9a99a, #e8c4b8)', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1rem' }}>🌸</div>
          <div>
            <div style={{ color: 'white', fontWeight: '700', fontSize: '0.95rem', fontFamily: "'Cormorant Garamond', serif" }}>EventHub</div>
            <div style={{ color: '#c9a99a', fontSize: '0.68rem' }}>Admin Panel</div>
          </div>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', background: 'rgba(201,169,154,0.1)', padding: '10px 12px', borderRadius: '12px', border: '1px solid rgba(201,169,154,0.2)' }}>
          <div style={{ width: '30px', height: '30px', background: 'linear-gradient(135deg, #c9a99a, #e8c4b8)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.85rem' }}>👤</div>
          <div>
            <div style={{ color: 'white', fontSize: '0.82rem', fontWeight: '600' }}>{user.name}</div>
            <div style={{ color: '#c9a99a', fontSize: '0.65rem' }}>Administrator</div>
          </div>
        </div>
      </div>

      {/* Nav */}
      <nav style={{ flex: 1, padding: '1rem 0.75rem' }}>
        {menuItems.map(item => (
          <Link key={item.path} to={item.path} style={{
            display: 'flex', alignItems: 'center', gap: '10px',
            padding: '11px 14px', borderRadius: '12px', marginBottom: '4px',
            textDecoration: 'none', fontSize: '0.85rem', fontWeight: '500',
            background: isActive(item.path) ? 'linear-gradient(135deg, #c9a99a, #e8c4b8)' : 'transparent',
            color: isActive(item.path) ? 'white' : 'rgba(255,255,255,0.5)',
            transition: 'all 0.2s',
            boxShadow: isActive(item.path) ? '0 4px 15px rgba(201,169,154,0.3)' : 'none'
          }}>
            <span>{item.icon}</span>
            <span>{item.label}</span>
          </Link>
        ))}
      </nav>

      {/* Footer */}
      <div style={{ padding: '0.75rem', borderTop: '1px solid rgba(201,169,154,0.15)' }}>
        <Link to="/home" style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '9px 14px', borderRadius: '10px', color: 'rgba(255,255,255,0.4)', textDecoration: 'none', fontSize: '0.8rem', marginBottom: '4px' }}>🏠 Back to Site</Link>
        <button onClick={handleLogout} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: '8px', padding: '9px 14px', borderRadius: '10px', background: 'transparent', border: 'none', color: '#e8a0a0', cursor: 'pointer', fontSize: '0.8rem' }}>🚪 Logout</button>
      </div>
    </aside>
  );
}
export default AdminSidebar;
